import{_ as t,c as i,ah as o,o as a}from"./chunks/framework.BjDJcZmr.js";const d=JSON.parse('{"title":"How to report an issue","description":"Creating an issue from a repository","frontmatter":{"date":"2025-07-03T00:00:00.000Z","title":"How to report an issue","category":"Guilty Crown","tags":["git"],"description":"Creating an issue from a repository"},"headers":[],"relativePath":"posts/report-an-issue.md","filePath":"posts/report-an-issue.md"}'),r={name:"posts/report-an-issue.md"};function s(l,e,n,u,p,h){return a(),i("div",null,e[0]||(e[0]=[o('<h1 id="how-to-report-an-issue" tabindex="-1">How to report an issue <a class="header-anchor" href="#how-to-report-an-issue" aria-label="Permalink to &quot;How to report an issue&quot;">​</a></h1><ol><li><p>确定仓库接受 ISSUE (有些仓库可能更倾向于——如：Discord)</p></li><li><p>搜索现有的 ISSUE，检查是否已有人报告相同或类似的问题</p></li><li><p>遵循仓库的模板：以下模板来自 <a href="https://github.com/RSSNext/Folo" target="_blank" rel="noreferrer">Folo</a></p><ul><li>🐞 Bug report</li><li>🚀 New feature proposal</li><li>🌐 Internationalization (i18n)</li><li>👀 Typo / Grammar fix</li><li>Reporting a Vulnerability</li><li>💬 Follow&#39;s Discord Server</li><li>Discuss an issue</li></ul></li><li><p>详细的信息</p><ul><li><p>Title</p></li><li><p>Platform：On which platforms does this bug occur?</p></li><li><p>Describe the bug：A clear and concise description of what the bug is. If you intend to submit a PR for this issue, tell us in the description. Thanks!</p></li><li><p>Entry ID：Please provide the entry id of the entry that is causing the issue. If you are not sure, please provide the entry url.</p></li><li><p>Relevant Information：Please provide your user id, feed id, feed url, or any other information that can help us reproduce the issue.</p></li><li><p>Reproduction Video：If possible, please provide a video that demonstrates the bug.</p></li><li><p>Environment：Please provide the environment in which you are using the application. You can find this information by going to Preferences &gt; About and clicking the copy button next to the version tag.</p></li><li><p>Validations：Before submitting the issue, please make sure you do the following</p><ul><li>Check that there isn&#39;t already an issue that reports the same bug to avoid creating a duplicate.*</li><li>Check that this is a concrete bug. For Q&amp;A, please open a GitHub Discussion instead.*</li><li>This issue is valid*</li></ul></li><li><p>Contributions：Please note that Open Source projects are maintained by volunteers, where your cases might not be always relevant to the others. It would make things move faster if you could help investigate and propose solutions.</p><ul><li>I am willing to submit a PR to fix this issue</li><li>I am willing to submit a PR with failing tests (actually just go ahead and do it, thanks!)</li></ul></li></ul></li></ol><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="http://www.catb.org/~esr/faqs/smart-questions.html" target="_blank" rel="noreferrer">How To Ask Questions The Smart Way</a></li><li><a href="https://github.com/ryanhanwu/How-To-Ask-Questions-The-Smart-Way/blob/main/README-zh_CN.md" target="_blank" rel="noreferrer">提问的智慧</a></li><li><a href="https://www.chiark.greenend.org.uk/~sgtatham/bugs-cn.html" target="_blank" rel="noreferrer">如何有效提交 bug</a></li></ul>',4)]))}const f=t(r,[["render",s]]);export{d as __pageData,f as default};
